import{_ as a,o as t,c as r,a0 as o}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Reprocess an Import","description":"","frontmatter":{},"headers":[],"relativePath":"imports/reprocess.md","filePath":"imports/reprocess.md"}'),s={name:"imports/reprocess.md"};function i(l,e,n,p,d,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="reprocess-an-import" tabindex="-1">Reprocess an Import <a class="header-anchor" href="#reprocess-an-import" aria-label="Permalink to &quot;Reprocess an Import&quot;">​</a></h1><p>Reprocessing is the area where the original plan was more ambitious than the current product.</p><h2 id="what-is-actually-supported-today" tabindex="-1">What is actually supported today <a class="header-anchor" href="#what-is-actually-supported-today" aria-label="Permalink to &quot;What is actually supported today&quot;">​</a></h2><p>The app does <strong>not</strong> currently support a live &quot;reprocess this existing import in place&quot; workflow.</p><p>Instead, the code path for reprocessing an existing saved import is not implemented yet. If you hit the dedicated reprocess endpoint, it returns a not-implemented result.</p><h2 id="what-to-do-instead" tabindex="-1">What to do instead <a class="header-anchor" href="#what-to-do-instead" aria-label="Permalink to &quot;What to do instead&quot;">​</a></h2><p>If you want a fresh OCR pass today:</p><ul><li>upload the screenshot again</li><li>switch provider first if that is the reason</li><li>review the new rows as a new import</li></ul><h2 id="important-warning-for-already-accepted-rows" tabindex="-1">Important warning for already accepted rows <a class="header-anchor" href="#important-warning-for-already-accepted-rows" aria-label="Permalink to &quot;Important warning for already accepted rows&quot;">​</a></h2><p>Because in-place reprocessing is not implemented, there is no supported &quot;rebuild the same import after some rows were already accepted&quot; story to rely on today.</p><p>If accepted data is already wrong, your safer choices are:</p><ul><li>fix the rows directly if the mistake is small</li><li>or use rollback through <a href="./delete-and-rollback.html">Delete an Import &amp; Roll Back Its Changes</a>, then restore or upload again as needed</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./choose-provider.html">Choose an Image-Processing Provider</a></li><li><a href="./import-mistakes.html">Fixing Import Mistakes</a></li></ul>',14)])])}const u=a(s,[["render",i]]);export{m as __pageData,u as default};
